import React, { useEffect, useState, useMemo } from "https://esm.sh/react@18.2.0";
import ReactDOM from "https://esm.sh/react-dom@18.2.0/client";
import { Video, Phone, Mail, Users, ChevronRight } from "https://esm.sh/lucide-react@0.284.0";

// Load Tailwind
if (!document.getElementById("tailwind-v4")) {
  const script = document.createElement("script");
  script.id = "tailwind-v4";
  script.src = "https://cdn.jsdelivr.net/npm/@tailwindcss/browser@4";
  document.head.appendChild(script);
}

// ICON (same logic)
const IconPicker = ({ type, active }) => {
  const t = type?.toLowerCase() || "";
  const color = active ? "#1d7eb9" : "#7c858c";

  if (t.includes("video")) return <Video size={20} color={color} />;
  if (t.includes("phone")) return <Phone size={20} color={color} />;
  if (t.includes("email")) return <Mail size={20} color={color} />;
  return <Users size={20} color={color} />;
};

const formatDate = (date) => {
  if (!date) return "-";

  const d = new Date(date);

  return d.toLocaleDateString("en-US", {
    month: "short",
    day: "2-digit",
    year: "numeric",
  });
};

function IZOConversationsList({ data }) {

  // ✅ SAME DATA HANDLING (robust)
  const safeData = useMemo(() => {
    if (Array.isArray(data)) return data;
    if (Array.isArray(data?.data)) return data.data;
    if (Array.isArray(data?.conversations)) return data.conversations;
    return [];
  }, [data]);

  const [selectedId, setSelectedId] = useState(null);

  useEffect(() => {
    if (safeData.length && !selectedId) {
      setSelectedId(
        safeData[0].conversation_id || safeData[0].id
      );
    }
  }, [safeData]);

  const selected = useMemo(() => {
    return safeData.find(
      (c) =>
        (c.conversation_id || c.id) === selectedId
    ) || safeData[0];
  }, [safeData, selectedId]);

  if (!safeData.length) {
    return <div className="p-4">No conversations</div>;
  }

  return (
    <div className="grid grid-cols-[7fr_13fr] h-screen font-[Inter]">

      {/* SIDEBAR */}
      <div className="flex flex-col overflow-auto">
        <div className="sticky top-0 z-10 px-3 pt-2 pb-1">
          <div className="text-[16px] font-semibold text-[#252726]">
            Previous Conversations
          </div>
        </div>

        <div className="flex-1 overflow-y-auto pt-4 flex flex-col gap-2.5">
          {safeData.map((item) => {
            const id = item.conversation_id || item.id;
            const isActive = selectedId === id;

            return (
              <div
                key={id}
                onClick={() => setSelectedId(id)}
                className={`w-full flex items-start justify-around p-2 cursor-pointer rounded-tl-lg rounded-bl-lg ${
                  isActive ? "bg-[#f6f8fa]" : "hover:bg-[#f6f8fa]/30"
                }`}
              >
                {/* ICON */}
                <div
                  className={`w-12 h-12 rounded-full flex items-center justify-center ${
                    isActive ? "bg-[#DAEFFA]" : "bg-[#f6f8fa]"
                  }`}
                >
                  <IconPicker type={item.type} active={isActive} />
                </div>

                {/* TEXT */}
                <div className="flex flex-col gap-1.5 flex-1 px-3 min-w-0">
                  <div title={item.title} className="text-[14px] font-semibold text-[#535862] truncate">
                    {item.title}
                  </div>

                  <div className="flex gap-2 text-[12px] text-[#7c858c]">
                    <span>{formatDate(item.date)}</span>
                    <span>|</span>
                    <span>
                      {item.duration ||
                        `${Math.floor(item.duration_minutes / 60)}hr ${
                          item.duration_minutes % 60
                        } mins`}
                    </span>
                  </div>
                </div>

                <ChevronRight className="w-5 h-5 text-[#252726]" />
              </div>
            );
          })}
        </div>
      </div>

      {/* CONTENT */}
      {selected && (
        <div className="bg-[#f6f8fa] rounded-lg p-6 overflow-auto">

          {/* HEADER */}
          <div className="flex items-start gap-4 mb-6">
            <div className="bg-white p-3 rounded-full">
              <IconPicker type={selected.type} />
            </div>

            <div className="flex flex-col gap-3">
              <div className="text-[16px] font-semibold text-[#252726]">
                {selected.title}
              </div>

              <div className="flex gap-4 text-[12px] text-[#7c858c]">
                <span>
                  Time:{" "}
                  <b className="text-[#7C858C]">
 			{selected.duration ||
                        `${Math.floor(selected.duration_minutes / 60)}hr ${
                          selected.duration_minutes % 60
                        } mins`}

                  </b>
                </span>
                <span className="font-semibold">
                  {formatDate(selected.date)}
                </span>
              </div>

              {selected.speakers && (
                <div className="text-[12px] text-[#7c858c]">
                  Speakers:{" "}
                  <b className="text-[#7C858C]">
                    {selected.speakers}
                  </b>
                </div>
              )}
            </div>
          </div>

          {/* META */}
          <div className="grid grid-cols-3 gap-2 mb-4">

  	    <div className="flex flex-col gap-2">
              <div className="text-[12px] font-semibold text-[#7c858c]">
                Category
              </div>
              <div className="text-[16px] font-medium text-[#535862]">
                {selected.category}
              </div>
            </div>



            <div className="flex flex-col gap-2">
              <div className="text-[12px] font-semibold text-[#7c858c]">
                Channel
              </div>
              <div className="text-[16px] font-medium text-[#535862]">
                {selected.type}
              </div>
            </div>
          </div>

          {/* DESCRIPTION */}
          {selected.note && (
            <div className="flex flex-col gap-2">
              <div className="text-[12px] font-semibold text-[#7c858c]">
                Description
              </div>

              <div className="space-y-4">
                {selected.note.split(". ").map((sentence, i, arr) => (
                  <div
                    key={i}
                    className="text-[16px] font-medium text-[#535862] leading-relaxed"
                  >
                    {sentence}
                    {i !== arr.length - 1 ? "." : ""}
                  </div>
                ))}
              </div>
            </div>
          )}
        </div>
      )}
    </div>
  );
}

// ToolJet mount
const ConnectedComponent = Tooljet.connectComponent(IZOConversationsList);

if (!window.tooljetRoot) {
  window.tooljetRoot = ReactDOM.createRoot(document.body);
}

window.tooljetRoot.render(<ConnectedComponent />);
